import{c as d,Z as n,Q as l,j as h,g as t,n as o,o as s,m as a,av as c}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse(`{"title":"Arm Scoped autonomy","description":"Mint a Scoped session on the dashboard to power prompt-free trading via the MCP broker and HavenBot's hands-off flows.","frontmatter":{"title":"Arm Scoped autonomy","description":"Mint a Scoped session on the dashboard to power prompt-free trading via the MCP broker and HavenBot's hands-off flows."},"headers":[],"relativePath":"guide/agent/set-tier.md","filePath":"guide/agent/set-tier.md","lastUpdated":1780229195000}`),g={name:"guide/agent/set-tier.md"};function p(u,e,m,y,f,b){const r=n("TaskMeta"),i=n("ExpectedResult");return l(),h("div",null,[e[1]||(e[1]=t("h1",{id:"arm-scoped-autonomy",tabindex:"-1"},[o("Arm Scoped autonomy "),t("a",{class:"header-anchor",href:"#arm-scoped-autonomy","aria-label":'Permalink to "Arm Scoped autonomy"'},"​")],-1)),s(r,{time:"~3 min",role:"Any signed-in user",needs:"Signed in with your passkey"}),e[2]||(e[2]=a('<blockquote><p><strong>What you&#39;ll do:</strong> mint a <strong>Scoped session</strong> on the dashboard — the signing grant that powers the <strong>MCP broker&#39;s</strong> prompt-free trading and HavenBot&#39;s hands-off flows (auto-reinvest, rebalance), within a cap and time limit you set.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>Be signed in with your passkey. You decide how much rope the agent gets, and you can change or revoke it anytime.</p></div><p>This is <strong>the enabling step</strong> for autonomous trading. With a Scoped session live, the <a href="/guide/mcp/arm-scoped">MCP broker</a> trades <strong>with no prompt at all</strong>, and HavenBot can run <strong>auto-reinvest</strong> and <strong>rebalance</strong> hands-off. (HavenBot&#39;s <em>individual</em> buy/sell still shows a one-tap confirmation card — see <a href="/guide/agent/autonomous">H4</a> — but only asks your device passkey once per session.)</p><h2 id="how-much-rope-you-can-give-the-agent" tabindex="-1">How much rope you can give the agent <a class="header-anchor" href="#how-much-rope-you-can-give-the-agent" aria-label="Permalink to &quot;How much rope you can give the agent&quot;">​</a></h2><p>You pick one of four tiers:</p><ul><li><strong>Advisory</strong> — read-only. Every write needs a fresh passkey signature.</li><li><strong>Confirm per action</strong> — the agent proposes; you confirm each write.</li><li><strong>Policy-bound</strong> — the agent writes within an allowlist plus spend caps.</li><li><strong>Scoped autonomy</strong> — grants capped, time-bounded signing within a <strong>per-trade cap</strong> and <strong>TTL</strong>. The <strong>MCP broker</strong> then trades with <strong>no prompt</strong>; HavenBot uses it for hands-off auto-reinvest + rebalance (and signs your confirmed buys/sells without re-asking your passkey each time).</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Go to <code>/agent/policy/transition</code> (you can also ask HavenBot to <em>&quot;open my agent settings&quot;</em>).</li><li>Leave the <strong>surface</strong> on <strong>MCP / Broker</strong> (the default). Scoped autonomy is minted on that surface, and <strong>HavenBot reuses the same session</strong> — so this one Scoped session powers both. If you switch the surface to HavenBot, the Scoped tier is intentionally disabled (with a hint to switch back).</li><li><strong>Pick the <code>Scoped autonomy</code> tier</strong> directly — there&#39;s no ladder to climb; any tier is one confirming tap away.</li><li>Set your <strong>per-trade cap</strong> (the maximum mhUSDC the agent can spend on a single trade — defaults to $100) and a <strong>TTL</strong> (how long the session stays valid).</li><li>Click <strong>Confirm transition</strong>, then <strong>approve with your passkey</strong>.</li><li>A <strong>session-key reveal modal</strong> opens. It mints a short-lived signing key <strong>on your device</strong> and surfaces it. For HavenBot in this same browser, you&#39;re done — the session is already active. (If you also run the MCP server, this is the key you&#39;ll hand to the broker — see <a href="/guide/mcp/arm-scoped">M1 · Arm Scoped autonomy on the dashboard</a>.)</li></ol><div class="info custom-block"><p class="custom-block-title">The Scoped key is minted on your device</p><p>The session key is generated <strong>client-side</strong> and is <strong>never sent over the wire</strong>. HavenBot gets time-boxed, capped signing rights — not your passkey.</p></div><div class="tip custom-block"><p class="custom-block-title">You can revoke it anytime</p><p>The same page shows a <strong>Revoke</strong> zone once a session is live, and you can lock the agent down instantly by asking HavenBot to <em>&quot;pause my agent&quot;</em>. Revoking or pausing blocks every write at once.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',12)),s(i,null,{default:c(()=>[...e[0]||(e[0]=[o(" After your passkey confirms, a ",-1),t("strong",null,"live Scoped session",-1),o(" exists — shown by the session banner and the revoke zone on the policy page. The MCP broker can now trade prompt-free up to your per-trade cap until the TTL expires, and HavenBot's auto-reinvest + rebalance run hands-off. ",-1)])]),_:1}),e[3]||(e[3]=a('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Scoped modal didn&#39;t mint a key</td><td>Cancel and reopen the modal; the key is generated locally, so retry on-device.</td></tr><tr><td>Want to lock the agent down fast</td><td>Ask HavenBot to <em>&quot;pause my agent&quot;</em>, or hit <strong>Revoke</strong> on the policy page — both block every write instantly.</td></tr><tr><td>Want to resume after pausing</td><td>Pick a tier again on the dashboard; your passkey installs a fresh session.</td></tr><tr><td>The cap or TTL won&#39;t accept your value</td><td>The per-trade cap must be at least <strong>$1 mhUSDC</strong> and the TTL must be one of the offered options.</td></tr></tbody></table><p>→ Next: <a href="/guide/agent/autonomous">Buy &amp; sell with HavenBot</a></p>',3))])}const w=d(g,[["render",p]]);export{k as __pageData,w as default};
